 Begin CmpMap 	# Compound Mapping
    Nin = 1 	# Number of input coordinates
 IsA Mapping 	# Mapping between coordinate systems
    MapA = 	# First component Mapping
       Begin CmpMap 	# Compound Mapping
          Nin = 1 	# Number of input coordinates
       IsA Mapping 	# Mapping between coordinate systems
          InvB = 1 	# Second Mapping used in inverse direction
          MapA = 	# First component Mapping
             Begin SwitchMap 	# Alternate regionalised Mapping
                Nin = 1 	# Number of input coordinates
             IsA Mapping 	# Mapping between coordinate systems
                FSMap = 	# Forward selector Mapping
                   Begin ZoomMap 	# Zoom about the origin
                      Nin = 1 	# Number of input coordinates
                   IsA Mapping 	# Mapping between coordinate systems
                      Zoom = 2 	# Zoom factor
                   End ZoomMap
                ISMap = 	# Inverse selector Mapping
                   Begin ZoomMap 	# Zoom about the origin
                      Nin = 1 	# Number of input coordinates
                   IsA Mapping 	# Mapping between coordinate systems
                      Zoom = 2 	# Zoom factor
                   End ZoomMap
                RMap1 = 	# Route Mapping
                   Begin ZoomMap 	# Zoom about the origin
                      Nin = 1 	# Number of input coordinates
                   IsA Mapping 	# Mapping between coordinate systems
                      Zoom = 3 	# Zoom factor
                   End ZoomMap
             End SwitchMap
          MapB = 	# Second component Mapping
             Begin SwitchMap 	# Alternate regionalised Mapping
                Nin = 1 	# Number of input coordinates
                Invert = 1 	# Mapping inverted
             IsA Mapping 	# Mapping between coordinate systems
                FSMap = 	# Forward selector Mapping
                   Begin ZoomMap 	# Zoom about the origin
                      Nin = 1 	# Number of input coordinates
                   IsA Mapping 	# Mapping between coordinate systems
                      Zoom = 2 	# Zoom factor
                   End ZoomMap
                ISMap = 	# Inverse selector Mapping
                   Begin ZoomMap 	# Zoom about the origin
                      Nin = 1 	# Number of input coordinates
                   IsA Mapping 	# Mapping between coordinate systems
                      Zoom = 2 	# Zoom factor
                   End ZoomMap
                RMap1 = 	# Route Mapping
                   Begin ZoomMap 	# Zoom about the origin
                      Nin = 1 	# Number of input coordinates
                   IsA Mapping 	# Mapping between coordinate systems
                      Zoom = 3 	# Zoom factor
                   End ZoomMap
             End SwitchMap
       End CmpMap
    MapB = 	# Second component Mapping
       Begin ZoomMap 	# Zoom about the origin
          Nin = 1 	# Number of input coordinates
       IsA Mapping 	# Mapping between coordinate systems
          Zoom = 7 	# Zoom factor
       End ZoomMap
 End CmpMap
